case productcatalog.MyNewPriceType:
    basePricer = rate.MyNew{}

// In openmeter/billing/rating/service/rate/mynew.go:
package rate

import (
    "github.com/openmeterio/openmeter/openmeter/billing/rating"
    "github.com/openmeterio/openmeter/pkg/timeutil"
)

var _ Pricer = MyNew{}

type MyNew struct{ NonProgressiveBillingPricer }

func (p MyNew) GenerateDetailedLines(in PricerCalculateInput) ([]rating.DetailedLine, error) {
    usage := in.GetUsage() // always call GetUsage(), never in.Usage directly
    _ = usage
    return []rating.DetailedLine{{...}}, nil
}

func (p MyNew) ResolveBillablePeriod(in rating.ResolveBillablePeriodInput) (*timeutil.ClosedPeriod, error) {
    return p.NonProgressiveBillingPricer.ResolveBillablePeriod(in)
}
